I have a thread pool sharing a single producer, so it would be more like this (excuse the bad code, it may hang):

```
import threading
import time
import Queue
import traceback
from workers import ConfluentKafkaProducer as Producer

PRODUCER = Producer()
STOP_THREADS = threading.Event()
QUEUE = Queue.Queue()

def run():
    while not STOP_THREADS.is_set():
        try:
            item = QUEUE.get()
            PRODUCER.send('drice_test', value=item)
        except:
            time.sleep(0.5)


def send(num_messages):
    for ii in range(0, num_messages):
        message = {}
        QUEUE.put(message)

if __name__ == '__main__':
    try:
        threads = []
        for ii in range(0, 100):
            thread = threading.Thread(target=run)
            thread.start()
        send(1000)
    except: 
        STOP_THREADS.set()
        traceback.print_exc()
        for thread in threads:
            thread.join()

```

